import React from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { ThemeProvider, createTheme, CssBaseline } from '@mui/material';
import { AuthProvider } from './context/AuthContext';
import Dashboard from './pages/Dashboard';
import Business from './pages/Business';
import BestIdea from './pages/BestIdea';
import Financial from './pages/Financial';
import Mindset from './pages/Mindset';
import Learning from './pages/Learning';
import Health from './pages/Health';
import Checkin from './pages/Checkin';
import Reports from './pages/Reports';
import AIAdvisor from './pages/AIAdvisor';
import Layout from './components/Layout';

const theme = createTheme({
  palette: {
    mode: 'light',
    primary:   { main: '#478559', contrastText: '#f5f0e8' },
    secondary: { main: '#161748', contrastText: '#f5f0e8' },
    background: { default: '#faf7f2', paper: '#ffffff' },
    text: { primary: '#1a1a2e', secondary: '#4f5f76' },
    success: { main: '#478559' },
    divider: 'rgba(71,133,89,0.15)',
  },
  typography: {
    fontFamily: '"Inter", "Segoe UI", "Roboto", sans-serif',
    h4: { fontWeight: 800, letterSpacing: '-0.5px' },
    h5: { fontWeight: 700, letterSpacing: '-0.3px' },
    h6: { fontWeight: 700 },
  },
  shape: { borderRadius: 12 },
  components: {
    MuiCard: {
      styleOverrides: {
        root: {
          backgroundImage: 'none',
          border: '1px solid rgba(71,133,89,0.12)',
          boxShadow: '0 2px 16px rgba(22,23,72,0.06)',
          transition: 'box-shadow 0.2s, transform 0.2s',
          '&:hover': {
            boxShadow: '0 8px 32px rgba(22,23,72,0.12)',
          }
        }
      }
    },
    MuiPaper: { styleOverrides: { root: { backgroundImage: 'none' } } },
    MuiButton: {
      styleOverrides: {
        root: {
          borderRadius: 10,
          textTransform: 'none',
          fontWeight: 600,
          transition: 'all 0.2s ease',
          '&:hover': { transform: 'translateY(-1px)', boxShadow: '0 4px 12px rgba(71,133,89,0.3)' },
        },
        contained: {
          background: 'linear-gradient(135deg, #478559 0%, #2d5c3d 100%)',
          color: '#f5f0e8',
          boxShadow: '0 2px 8px rgba(71,133,89,0.3)',
        }
      }
    },
    MuiChip: {
      styleOverrides: {
        root: { fontWeight: 600, borderRadius: 8 }
      }
    },
    MuiTextField: {
      styleOverrides: {
        root: {
          '& .MuiOutlinedInput-root': {
            borderRadius: 10,
            bgcolor: '#ffffff',
            '& fieldset': { borderColor: 'rgba(71,133,89,0.25)' },
            '&:hover fieldset': { borderColor: '#478559' },
            '&.Mui-focused fieldset': { borderColor: '#478559' },
          }
        }
      }
    },
    MuiAccordion: {
      styleOverrides: {
        root: {
          border: '1px solid rgba(71,133,89,0.15)',
          boxShadow: 'none',
          borderRadius: '10px !important',
          '&:before': { display: 'none' },
          '&.Mui-expanded': {
            boxShadow: '0 4px 16px rgba(22,23,72,0.08)',
          }
        }
      }
    },
    MuiLinearProgress: {
      styleOverrides: {
        root: { borderRadius: 8, backgroundColor: 'rgba(71,133,89,0.12)' },
        bar: { borderRadius: 8, backgroundColor: '#478559' }
      }
    },
    MuiTabs: {
      styleOverrides: {
        indicator: { backgroundColor: '#478559', height: 3, borderRadius: 3 }
      }
    },
    MuiTab: {
      styleOverrides: {
        root: {
          textTransform: 'none',
          fontWeight: 600,
          color: '#4f5f76',
          '&.Mui-selected': { color: '#478559' },
        }
      }
    },
    MuiDivider: {
      styleOverrides: { root: { borderColor: 'rgba(71,133,89,0.12)' } }
    },
    MuiCheckbox: {
      styleOverrides: {
        root: {
          color: 'rgba(71,133,89,0.3)',
          '&.Mui-checked': { color: '#478559' }
        }
      }
    }
  }
});

function App() {
  return (
    <ThemeProvider theme={theme}>
      <CssBaseline />
      <AuthProvider>
        <BrowserRouter>
          <Routes>
            <Route path="/" element={<Layout />}>
              <Route index element={<Dashboard />} />
              <Route path="business" element={<Business />} />
              <Route path="best-idea" element={<BestIdea />} />
              <Route path="financial" element={<Financial />} />
              <Route path="mindset" element={<Mindset />} />
              <Route path="learning" element={<Learning />} />
              <Route path="health" element={<Health />} />
              <Route path="checkin" element={<Checkin />} />
              <Route path="reports" element={<Reports />} />
              <Route path="ai" element={<AIAdvisor />} />
            </Route>
            <Route path="*" element={<Navigate to="/" />} />
          </Routes>
        </BrowserRouter>
      </AuthProvider>
    </ThemeProvider>
  );
}

export default App;
